fn default_board_id(db: &shell::Db) -> Result<String> {
    let boards = shell::list_boards(db)?;
    boards
        .first()
        .map(|b| b.id.clone())
        .ok_or_else(|| anyhow!("no boards found; run 'kanban init' first"))
}

fn load_default_board_state(db: &shell::Db) -> Result<crate::core::BoardState> {
    let board_id = default_board_id(db)?;
    db.load_board_state(&board_id)
        .map_err(|_| anyhow!("board not found"))
}

/// Load column names from the default board for interactive prompting.
fn load_column_names(db: &shell::Db) -> Result<Vec<String>> {
    let state = load_default_board_state(db)?;
    Ok(state.columns.iter().map(|c| c.name.clone()).collect())
}

// ── Exit code wrapper ──────────────────────────────────────────────────────

/// Run the CLI, handling exit codes per the spec.
pub fn run_with_exit() {
    match run() {
        Ok(()) => process::exit(0),
        Err(err) => {
            eprintln!("error: {}", err);
            let exit_code = if err.root_cause().is::<std::io::Error>() {
                2
            } else {
                1
            };
            process::exit(exit_code);
        }
    }
}

use std::path::PathBuf;

/// Resolve the database path using priority: CLI flag > KANBAN_DB env var > XDG default.
///
/// If `cli_path` is `Some`, it takes highest priority.
/// Otherwise, the `KANBAN_DB` environment variable is checked.
/// Finally, the XDG default (`$XDG_DATA_HOME/kanban/kanban.db` or `~/.local/share/kanban/kanban.db`) is used.
pub fn resolve_db_path(cli_path: Option<&str>) -> PathBuf {
    if let Some(path) = cli_path {
        return PathBuf::from(path);
    }

    if let Ok(path) = std::env::var("KANBAN_DB") {
        return PathBuf::from(path);
    }

    xdg_default_path()
}

/// Compute the XDG default database path.
fn xdg_default_path() -> PathBuf {
    if let Some(data_home) = std::env::var_os("XDG_DATA_HOME") {
        return PathBuf::from(data_home).join("kanban").join("kanban.db");
    }

    // Fallback to ~/.local/share/kanban/kanban.db
    if let Some(base_dir) = dirs::data_local_dir() {
        return base_dir.join("kanban").join("kanban.db");
    }

    // Last resort fallback
    PathBuf::from(".kanban.db")
}

