use anyhow::{anyhow, Result};
use dialoguer::{Confirm, Input, Select};

/// Prompt for text input with a label.
/// Returns `Err` if stdin is not a TTY (caller should handle non-interactive error).
pub fn prompt_input<T: std::fmt::Display>(prompt: &str, default: Option<&str>) -> Result<String> {
    let mut builder = Input::<String>::new().with_prompt(prompt);
    if let Some(d) = default {
        builder = builder.default(d.to_string());
    }
    builder.interact_text().map_err(Into::into)
}

/// Prompt for a selection from a list.
/// Returns the selected index.
pub fn prompt_select(items: &[&str], prompt: &str) -> Result<usize> {
    let selection = Select::new().with_prompt(prompt).items(items).interact()?;
    Ok(selection)
}

/// Prompt for a yes/no confirmation.
/// Returns `true` if the user confirms.
pub fn prompt_confirm(prompt: &str) -> Result<bool> {
    let confirmed = Confirm::new()
        .with_prompt(prompt)
        .default(false)
        .interact()?;
    Ok(confirmed)
}

/// Check if stdin is a TTY (interactive).
pub fn is_interactive() -> bool {
    atty::is(atty::Stream::Stdin)
}

/// Prompt for a required value. If already provided in `value`, return it.
/// If interactive (is_tty), prompt the user. If not interactive, return an error.
/// `choices` provides a selection list if non-empty; otherwise free-form input.
pub fn prompt_required(
    value: Option<String>,
    label: &str,
    is_tty: bool,
    choices: &[String],
) -> Result<String> {
    if let Some(v) = value {
        return Ok(v);
    }

    if !is_tty {
        return Err(anyhow!(
            "missing required argument: '{}'. Provide it or run interactively.",
            label.to_lowercase()
        ));
    }

    if !choices.is_empty() {
        let selection = Select::new()
            .with_prompt(label)
            .items(choices)
            .default(0)
            .interact()
            .map_err(|e| anyhow!("{}", e))?;
        Ok(choices[selection].clone())
    } else {
        let input: String = Input::new()
            .with_prompt(label)
            .interact_text()
            .map_err(|e| anyhow!("{}", e))?;
        if input.trim().is_empty() {
            return Err(anyhow!("{} cannot be empty", label));
        }
        Ok(input.trim().to_string())
    }
}

/// Show a confirmation summary for task addition and ask for confirmation.
pub fn confirm_task_add(
    title: &str,
    column: &str,
    desc: &str,
    priority: &str,
    is_tty: bool,
) -> Result<bool> {
    if !is_tty {
        return Ok(true);
    }

    println!("Task summary:");
    println!("  Title:    {}", title);
    println!("  Column:   {}", column);
    if !desc.is_empty() {
        println!("  Desc:     {}", desc);
    }
    println!("  Priority: {}", priority);

    Confirm::new()
        .with_prompt("Add this task?")
        .default(true)
        .interact()
        .map_err(|e| anyhow!("{}", e))
}

use crate::core::{Board, BoardState, Column, Task};

/// Render a board state as a text board view.
pub fn render_board(state: &BoardState) -> String {
    let mut out = String::new();
    out.push_str(&format!(
        "Board: {} (id: {})\n\n",
        state.board.name, state.board.id
    ));

    for col in &state.columns {
        let tasks: Vec<&Task> = state
            .tasks
            .iter()
            .filter(|t| t.column_id == col.id)
            .collect();
        out.push_str(&format!("  [{}] ({})\n", col.name, tasks.len()));
        for task in tasks {
            let prio_name = state
                .priorities
                .iter()
                .find(|p| p.id == task.priority_id)
                .map(|p| p.name.as_str())
                .unwrap_or("?");
            out.push_str(&format!(
                "    {}  {} [{}]\n",
                task.id, task.title, prio_name
            ));
        }
        out.push('\n');
    }

    out
}

/// Render a list of boards as text lines.
pub fn render_boards(boards: &[Board]) -> String {
    let mut out = String::new();
    for board in boards {
        out.push_str(&format!("  {}  {}\n", board.id, board.name));
    }
    out
}

/// Render a list of columns as text lines.
pub fn render_columns(columns: &[Column]) -> String {
    let mut out = String::new();
    for col in columns {
        out.push_str(&format!(
            "  {}  {}  (pos: {})\n",
            col.id, col.name, col.position
        ));
    }
    out
}

/// Render a list of tasks as text lines.
pub fn render_tasks(tasks: &[Task]) -> String {
    let mut out = String::new();
    for task in tasks {
        out.push_str(&format!("  {}  {}\n", task.id, task.title));
    }
    out
}

/// Render a single task as text lines.
pub fn render_task(task: &Task, state: &BoardState) -> String {
    let prio_name = state
        .priorities
        .iter()
        .find(|p| p.id == task.priority_id)
        .map(|p| p.name.as_str())
        .unwrap_or("?");
    let col_name = state
        .columns
        .iter()
        .find(|c| c.id == task.column_id)
        .map(|c| c.name.as_str())
        .unwrap_or("?");

    format!(
        "ID:          {}\n\
         Title:       {}\n\
         Description: {}\n\
         Priority:    {}\n\
         Column:      {}\n\
         Position:    {}\n\
         Created:     {}\n\
         Updated:     {}\n",
        task.id,
        task.title,
        task.description,
        prio_name,
        col_name,
        task.position,
        task.created_at,
        task.updated_at
    )
}

use crate::core::error::IdError;

/// Resolve a short ID prefix to a full ID.
///
/// Returns the matched full ID if exactly one candidate starts with the prefix,
/// `IdError::Ambiguous` if multiple match, or `IdError::NotFound` if none match.
pub fn resolve_id(prefix: &str, candidates: &[&str]) -> Result<String, IdError> {
    let matches: Vec<&str> = candidates
        .iter()
        .copied()
        .filter(|id| id.starts_with(prefix))
        .collect();

    match matches.len() {
        0 => Err(IdError::NotFound {
            prefix: prefix.to_string(),
        }),
        1 => Ok(matches[0].to_string()),
        _ => Err(IdError::Ambiguous {
            prefix: prefix.to_string(),
            matches: matches.iter().map(|s| s.to_string()).collect(),
        }),
    }
}

/// Compute the minimum unique prefix length for each ID in the set.
///
/// For each ID, find the shortest prefix that distinguishes it from every other ID.
/// Returns a vector of `(id, min_prefix_length)` pairs.
pub fn min_unique_prefixes(ids: &[&str]) -> Vec<(String, usize)> {
    if ids.is_empty() {
        return vec![];
    }
    ids.iter()
        .map(|&id| {
            let min_len = ids
                .iter()
                .filter(|&&other| other != id)
                .map(|&other| {
                    // Find the first position where id and other differ.
                    // The minimum prefix must extend at least that far.
                    let diff_pos = id
                        .chars()
                        .zip(other.chars())
                        .position(|(a, b)| a != b)
                        .unwrap_or(id.len());
                    diff_pos + 1
                })
                .max()
                .unwrap_or(1) // If it's the only ID, minimum prefix is 1 char
                .min(id.len());
            (id.to_string(), min_len)
        })
        .collect()
}

