Action::MoveTaskDown => {
    if let Some(task) = app.focused_task() {
        if let Some(ref state) = app.state {
            let col_tasks: Vec<&crate::core::Task> = state
                .tasks
                .iter()
                .filter(|t| t.column_id == task.column_id)
                .collect();
            let current_pos = task.position;
            let next_tasks: Vec<i32> = col_tasks
                .iter()
                .filter(|t| t.position > current_pos)
                .map(|t| t.position)
                .collect();
            if let Some(&next_pos) = next_tasks.first() {
                // Swap positions
                let target_task = col_tasks
                    .iter()
                    .find(|t| t.position == next_pos && t.id != task.id);
                if let Some(target) = target_task {
                    let now = chrono::Utc::now().to_rfc3339();
                    let tx = db.conn_mut().transaction().context("tx fail")?;
                    tx.execute(
                        "UPDATE task SET position = ?1, updated_at = ?2 WHERE id = ?3",
                        rusqlite::params![current_pos, now.clone(), target.id],
                    )
                    .context("swap fail")?;
                    tx.execute(
                        "UPDATE task SET position = ?1, updated_at = ?2 WHERE id = ?3",
                        rusqlite::params![next_pos, now, task.id],
                    )
                    .context("swap fail")?;
                    tx.commit().context("commit fail")?;
                    app.focused_task_idx += 1;
                    Ok((true, false))
                } else {
                    app.set_error("Swap failed".into());
                    Ok((false, false))
                }
            } else {
                app.set_error("Already at bottom".into());
                Ok((false, false))
            }
        } else {
            Ok((false, false))
        }
    } else {
        app.set_error("No task selected".into());
        Ok((false, false))
    }
}
